#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1005;
const ll inf=1e17;
int n,s,t,fir[N],a[N],dp[N];
struct node
{
	int v,w,fan;
};
ll lev[N];
vector<node> g[N];
void add(int u,int v,ll w,bool flag)
{
	if(flag)
	{
		if((u==1)||(u==n*2)||(v==1)||(v==n*2)) w=inf;
	}
	g[u].push_back(node{v,w,g[v].size()});
	g[v].push_back(node{u,0,g[u].size()-1});
}
bool bfs()
{
	for(int i=0;i<=2*n+1;i++)
	{
		lev[i]=inf;
		fir[i]=0;
	}
	queue<int> q;
	q.push(s);
	lev[s]=0;
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].w;
			if((w>0)&&(lev[v]==inf))
			{
				q.push(v);
				lev[v]=lev[u]+1;
				if(v==t) return 1;
			}
		}
	}
	return 0;
}
ll dfs(int u,ll mn)
{
	if(u==t) return mn;
	ll ans=0;
	for(int i=fir[u];i<g[u].size();i++)
	{
		fir[u]=i;
		int v=g[u][i].v,w=g[u][i].w;
		if((w>0)&&(lev[v]==lev[u]+1))
		{
			ll num=dfs(v,min(mn,(ll)w));
			if(num==0) lev[v]=inf;
			g[u][i].w-=num;
			g[v][g[u][i].fan].w+=num;
			ans+=num;
			mn-=num;
		}
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen("P2766_5.in","r",stdin);
//	freopen("my.out","w",stdout);
	cin>>n;
	s=0,t=2*n+1;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		dp[i]=1;
	}
	int mx=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<i;j++)
		{
			if(a[j]<=a[i]) dp[i]=max(dp[i],dp[j]+1);
		}
		mx=max(mx,dp[i]);
	}
	if(mx==1)
	{
		cout<<mx<<"\n"<<n<<"\n"<<n;
		return 0;
	}
	cout<<mx<<"\n";
	for(int i=1;i<=n;i++)
	{
		add(i,i+n,1,0);
		if(dp[i]==1) add(s,i,1,0);
		if(dp[i]==mx) add(i+n,t,1,0);
		for(int j=i+1;j<=n;j++)
		{
			if((a[i]<=a[j])&&((dp[i]+1)==dp[j]))
			{
				add(i+n,j,1,0);
			}
		}
	}
	ll ans=0;
	while(bfs())
	{
		ans+=dfs(s,inf);
	}
	cout<<ans<<"\n";
	ans=0;
	for(int i=0;i<=n*2+1;i++) g[i].clear();
	memset(fir,0,sizeof(fir));
	for(int i=1;i<=n;i++)
	{
		add(i,i+n,1,1);
		if(dp[i]==1) add(s,i,1,1);
		if(dp[i]==mx) add(i+n,t,1,1);
		for(int j=i+1;j<=n;j++)
		{
			if(a[i]<=a[j]&&dp[i]+1==dp[j])
			{
				add(i+n,j,1,1);
			}
		}
	}
	while(bfs())
	{
		ans+=dfs(s,inf);
	}
	cout<<ans<<"\n";
	return 0;
}
